		}
		.onReceive(discoverAgentVM.$pendingQuestion) { _ in
			syncContextBuilderQuestionPresentation()
		}
		.onChange(of: agentModeVM.activeTranscriptPresentationRevision) { _, _ in refreshRuntimeMetrics() }
		.onChange(of: agentModeVM.activeTranscriptPerformanceSnapshot) { _, _ in refreshRuntimeMetrics() }
		.onChange(of: agentModeVM.contextUsage) { _, _ in refreshRuntimeMetrics() }
		.onChange(of: promptManager.fileManager.selectedFiles.count) { _, _ in refreshRuntimeMetrics() }
		.onChange(of: agentModeVM.selectedAgent) { _, _ in refreshRuntimeMetrics() }
		.onChange(of: currentTabID) { _, tabID in
			syncContextBuilderQuestionPresentation()
			stressHarness?.bootstrapIfNeeded(currentTabID: tabID)
		}
		.onDisappear { stressHarness?.pause() }
		#else
		AgentModeChatDetailView(
			agentModeVM: agentModeVM,
			discoverAgentVM: discoverAgentVM,
			isContextBuilderQuestionPresented: isContextBuilderQuestionPresented,
			chatViewModel: chatViewModel,
			promptManager: promptManager,
			runtimeVM: runtimeVM,
			windowID: windowID,
			currentTabID: currentTabID
		)
