		.onChange(of: currentTabID) { _, _ in
			syncContextBuilderQuestionPresentation()
		}
		#endif
	}

	private func refreshRuntimeMetrics() {
		runtimeVM.update(
			snapshot: agentModeVM.activeTranscriptAnalyticsSnapshot,
