internal enum ToolCardAccentResolver {
	static func family(for toolName: String?) -> ClusterToolCategory.ToolFamily {
		guard let normalized = normalizedToolName(toolName)?.lowercased() else {
			return .other
		}
		return ClusterToolCategory.classification(forNormalizedToolName: normalized).family
	}

	static func color(for toolName: String?) -> Color {
		switch family(for: toolName) {
		case .navigation:
			return BubbleColors.toolNavigationAccent
		case .edit:
			return BubbleColors.toolEditAccent
		case .execution:
			return BubbleColors.toolExecutionAccent
		case .communication:
			return BubbleColors.toolCommunicationAccent
		case .config:
			return BubbleColors.toolConfigAccent
		case .other:
			return BubbleColors.toolOtherAccent
		}
	}

	private static func normalizedToolName(_ name: String?) -> String? {
		guard let raw = name?.trimmingCharacters(in: .whitespacesAndNewlines), !raw.isEmpty else { return nil }
		let prefix = "mcp__RepoPrompt__"
		let stripped: String
		if raw.hasPrefix(prefix) {
			stripped = String(raw.dropFirst(prefix.count))
		} else {
			stripped = raw
		}
		let suffix = stripped.split(separator: ".").last.map(String.init) ?? stripped
		let lowered = suffix.lowercased()
		if lowered == "local_shell" || lowered == "shell" || lowered == "unified_exec" || lowered == "exec_command" || lowered == "run_shell_command" {
			return "bash"
		}
		if lowered == "web_search" || lowered == "web_search_request" || lowered == "google_web_search" || lowered == "search_web" {
			return "search"
		}
		if lowered == "filechange" || lowered == "file_change" {
			return "apply_patch"
		}
		return suffix
	}
}
",
  "verbose" : true
}

