	private func averageDurationNanoseconds(iterations: Int, _ work: () -> Void) -> Double {
		let clock = ContinuousClock()
		var samples: [Double] = []
		samples.reserveCapacity(iterations)
		for _ in 0..<iterations {
			let duration = clock.measure {
				work()
