      mcpConnectTimeoutMs: 1000,
      mcpToolTimeoutMs: 1000,
      daemonStateDir: "/tmp/xcodetester-state",
      daemonStartupTimeoutMs: 1000,
      scheme: "RepoPrompt",
      configuration: "Debug",
      derivedDataBasePath: "/tmp/DerivedData",
      fallbackCleanup: true,
      toolHints: {
        build: "BuildProject",
      },
    },
    commands: [],
  };

  const calls: string[] = [];
  const report = await invokeXcodeCommand(
    {
      config,
      mcp: {
        listTools: async () => [{ name: "BuildProject" }],
        callTool: async (_server: string, toolName: string) => {
          calls.push(toolName);
          if (toolName === "BuildProject") {
            return {
              isError: false,
              structuredContent: {
                buildResult: "The build failed",
                errors: [],
              },
            };
          }
          if (toolName === "GetBuildLog") {
            return {
              structuredContent: {
                buildLogEntries: [
                  {
                    emittedIssues: [
                      {
                        path: "/tmp/Stale.swift",
                        line: 42,
                        message: "stale diagnostic",
                        severity: "error",
                      },
                    ],
                  },
                ],
              },
            };
          }
          return { isError: true, content: [{ type: "text", text: `Unexpected tool: ${toolName}` }] };
        },
      } as never,
      globalFlags: {},
      log: () => undefined,
    },
    "build",
    {},
  );

  const structured = report.result.structuredContent as Record<string, unknown>;
  assert.equal(report.route, "mcp");
  assert.deepEqual(calls, ["BuildProject"]);
  assert.deepEqual(structured.errors, []);
  assert.equal(structured.buildLogEntries, undefined);
});

